mapper.select:
 SELECT  FROM collect c 

	 order by ${query.orderBy}


	 limit #{query.simplePage.start},#{query.simplePage.end}

select * from collect c
where c.user_id = #{userId}
and c.video_id is not null

SELECT * FROM collect c
where c.user_id = #{query.userId}
and c.favorite = #{query.favorite}
and c.video_id is not null
 order by c.create_time asc

	limit #{query.simplePage.start},#{query.simplePage.end}

select * from collect c join video v on c.video_id = v.video_id
where c.user_id = #{query.userId}
and c.favorite = #{query.favorite}
and c.video_id is not null
order by CAST(v.play_count AS UNSIGNED) desc

	limit #{query.simplePage.start},#{query.simplePage.end}

select * from collect c join video v on c.video_id = v.video_id
where c.user_id = #{query.userId}
and c.favorite = #{query.favorite}
and c.video_id is not null
order by v.create_time desc

	limit #{query.simplePage.start},#{query.simplePage.end}
